229→export const clipboardDb = {
230→  async getAll(limit = 1000): Promise<ClipboardEntryRow[]> {
231→    if (isTauri) {
232→      const db = await getDb();
233→      return db.select<ClipboardEntryRow[]>(
234→        'SELECT id, content, content_type, source_app, copied_at, pinned FROM clipboard_entries ORDER BY pinned DESC, copied_at DESC LIMIT $1',
235→        [limit],
236→      );
237→    }
238→    return storageGet('clipboard-history', isClipboardRowArray) ?? [];
239→  },
240→  async insert(entry: ClipboardEntryRow): Promise<void> {
241→    if (isTauri) {
242→      const db = await getDb();
243→      await db.execute(
244→        'INSERT INTO clipboard_entries (id, content, content_type, source_app, copied_at, pinned) VALUES ($1, $2, $3, $4, $5, $6)',
245→        [
246→          entry.id,
247→          entry.content,
248→          entry.content_type,
249→          entry.source_app,
250→          entry.copied_at,
251→          entry.pinned,
252→        ],
253→      );
254→      return;
255→    }
256→    const all = await this.getAll();
257→    all.unshift(entry);
258→    storageSet('clipboard-history', all);
259→  },
260→  async update(
261→    id: string,
262→    updates: Partial<Omit<ClipboardEntryRow, 'id'>>,
263→  ): Promise<void> {
264→    if (isTauri) {
265→      const db = await getDb();
266→      const query = buildUpdateQuery(
267→        'clipboard_entries',
268→        updates,
269→        CLIPBOARD_COLUMNS,
270→        id,
271→      );
272→      if (!query) return;
273→      await db.execute(query.sql, query.values);
274→      return;
275→    }
276→    const all = await this.getAll();
277→    const updated = all.map(r =>
278→      r.id === id
279→        ? {
280→            ...r,
281→            ...updates,
282→          }
283→        : r);
284→    storageSet('clipboard-history', updated);
285→  },
286→  async delete(id: string): Promise<void> {
287→    if (isTauri) {
288→      const db = await getDb();
289→      await db.execute('DELETE FROM clipboard_entries WHERE id = $1', [id]);
290→      return;
291→    }
292→    const all = await this.getAll();
293→    storageSet(
294→      'clipboard-history',
295→      all.filter(r => r.id !== id),
296→    );
297→  },
298→  async clear(): Promise<void> {
299→    if (isTauri) {
300→      const db = await getDb();
301→      await db.execute('DELETE FROM clipboard_entries');
302→      return;
303→    }
304→    storageRemove('clipboard-history');
305→  },
306→  async search(query: string, limit = 50): Promise<ClipboardEntryRow[]> {
307→    if (isTauri) {
308→      const escaped = escapeFts5Query(query);
309→      if (!escaped) return [];
310→      const db = await getDb();
311→      return db.select<ClipboardEntryRow[]>(
312→        `SELECT ce.id, ce.content, ce.content_type, ce.source_app, ce.copied_at, ce.pinned
313→         FROM clipboard_entries ce
314→         JOIN clipboard_entries_fts fts ON ce.rowid = fts.rowid
315→         WHERE clipboard_entries_fts MATCH $1
316→         ORDER BY ce.pinned DESC, ce.copied_at DESC
317→         LIMIT $2`,
318→        [
319→          escaped,
320→          limit,
321→        ],
322→      );
323→    }
324→    const all = await this.getAll();
325→    const q = query.toLowerCase();
326→    return all.filter(r => r.content.toLowerCase().includes(q)).slice(0, limit);
327→  },
328→};
